#include <iostream>
#include <stack>
using namespace std;
stack<char> a;
int main()
{
    int n;
    cin>>n;
    for(int i=0;i<=n-1;i++)
    {
        string s;
        cin>>s;
        bool flag=true;
        for(int j=0;j<=s.size()-1;j++)
        {
            if(s[j]=='(')
            {
                a.push(')');
            }
            else if(s[j]=='[')
            {
                a.push(']');
            }
            else if(s[j]==')'||s[j]==']')
            {
                if(a.empty()||a.top()!=s[j])
                {
                    flag=false;
                    break;
                }
                else
                {
                    a.pop();
                }
            }
        }
        if(flag&&a.empty())
        {
            cout<<"Yes"<<endl;
        }
        else
        {
            cout<<"No"<<endl;
            while(!(a.empty()))
            {
                a.pop();
            }
        }
    }
    return 0;
}
